/**
 * Pure validation functions for order operations.
 *
 * These validators contain no side effects and no database calls.
 * They validate data shape and business rules that don't require external state.
 */

import type { OrderItem, OrderStatus, CreateOrderInput } from '../models/order.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that an order has at least one item.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate the input for creating an order.
 * Does NOT check whether the user exists (that requires a database call).
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  validateOrderItems(input.items);
}

/**
 * Pure validation functions for user operations.
 *
 * These validators contain no side effects and no database calls.
 * They validate data shape and business rules that don't require external state.
 */

import type { CreateUserInput, UpdateUserInput } from '../models/user.js';

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that an email address has a valid format.
 */
export function validateEmail(email: string): void {
  if (!EMAIL_REGEX.test(email)) {
    throw new Error(`Invalid email format: ${email}`);
  }
}

/**
 * Validate the input for creating a user.
 * Does NOT check email uniqueness (that requires a database call).
 */
export function validateCreateUserInput(input: CreateUserInput): void {
  if (!input.name || input.name.trim().length === 0) {
    throw new Error('User name is required');
  }
  validateEmail(input.email);
}

/**
 * Validate the input for updating a user.
 * Does NOT check email uniqueness (that requires a database call).
 */
export function validateUpdateUserInput(input: UpdateUserInput): void {
  if (input.name !== undefined && input.name.trim().length === 0) {
    throw new Error('User name cannot be empty');
  }
  if (input.email !== undefined) {
    validateEmail(input.email);
  }
}

/**
 * Pure validation functions for user preferences operations.
 *
 * These validators contain no side effects and no database calls.
 * They validate data shape and business rules that don't require external state.
 */

import type { CreatePreferencesInput, UpdatePreferencesInput } from '../models/user-preferences.js';

const VALID_FREQUENCIES = ['immediate', 'daily-digest', 'weekly-digest'] as const;

/**
 * Validate the input for creating preferences.
 * Does NOT check user existence or duplicate preferences (those require database calls).
 */
export function validateCreatePreferencesInput(input: CreatePreferencesInput): void {
  if (!input.userId || input.userId.trim().length === 0) {
    throw new Error('userId is required');
  }
  if (input.emailFrequency !== undefined && !VALID_FREQUENCIES.includes(input.emailFrequency)) {
    throw new Error(`Invalid email frequency: ${input.emailFrequency}`);
  }
}

/**
 * Validate the input for updating preferences.
 */
export function validateUpdatePreferencesInput(input: UpdatePreferencesInput): void {
  if (input.emailFrequency !== undefined && !VALID_FREQUENCIES.includes(input.emailFrequency)) {
    throw new Error(`Invalid email frequency: ${input.emailFrequency}`);
  }
}

