import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateOrderItems,
  validateCreateOrderInput,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });

    it('should reject shipped -> cancelled', () => {
      expect(isValidStatusTransition('shipped', 'cancelled')).toBe(false);
    });
  });

  describe('validateOrderItems', () => {
    it('should accept non-empty items array', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items array', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('validateCreateOrderInput', () => {
    it('should accept valid input', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
        }),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmail,
  validateCreateUserInput,
  validateUpdateUserInput,
} from '../../src/validators/user.validator.js';

describe('User Validators', () => {
  describe('validateEmail', () => {
    it('should accept valid email', () => {
      expect(() => validateEmail('alice@example.com')).not.toThrow();
    });

    it('should accept email with subdomain', () => {
      expect(() => validateEmail('alice@mail.example.com')).not.toThrow();
    });

    it('should reject email without @', () => {
      expect(() => validateEmail('aliceexample.com')).toThrow('Invalid email format');
    });

    it('should reject email without domain', () => {
      expect(() => validateEmail('alice@')).toThrow('Invalid email format');
    });

    it('should reject email without local part', () => {
      expect(() => validateEmail('@example.com')).toThrow('Invalid email format');
    });

    it('should reject empty string', () => {
      expect(() => validateEmail('')).toThrow('Invalid email format');
    });

    it('should reject email with spaces', () => {
      expect(() => validateEmail('alice @example.com')).toThrow('Invalid email format');
    });
  });

  describe('validateCreateUserInput', () => {
    it('should accept valid input', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).not.toThrow();
    });

    it('should throw for empty name', () => {
      expect(() =>
        validateCreateUserInput({
          name: '',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toThrow('User name is required');
    });

    it('should throw for whitespace-only name', () => {
      expect(() =>
        validateCreateUserInput({
          name: '   ',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toThrow('User name is required');
    });

    it('should throw for invalid email', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: 'not-an-email',
          role: 'member',
        }),
      ).toThrow('Invalid email format');
    });
  });

  describe('validateUpdateUserInput', () => {
    it('should accept valid partial input', () => {
      expect(() => validateUpdateUserInput({ name: 'Bob' })).not.toThrow();
    });

    it('should accept empty input (no changes)', () => {
      expect(() => validateUpdateUserInput({})).not.toThrow();
    });

    it('should throw for empty name', () => {
      expect(() => validateUpdateUserInput({ name: '' })).toThrow(
        'User name cannot be empty',
      );
    });

    it('should throw for invalid email', () => {
      expect(() =>
        validateUpdateUserInput({ email: 'bad-email' }),
      ).toThrow('Invalid email format');
    });

    it('should accept valid email update', () => {
      expect(() =>
        validateUpdateUserInput({ email: 'new@example.com' }),
      ).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateCreatePreferencesInput,
  validateUpdatePreferencesInput,
} from '../../src/validators/preferences.validator.js';

describe('Preferences Validators', () => {
  describe('validateCreatePreferencesInput', () => {
    it('should accept valid input with only userId', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: 'user-1' }),
      ).not.toThrow();
    });

    it('should accept valid input with all fields', () => {
      expect(() =>
        validateCreatePreferencesInput({
          userId: 'user-1',
          emailEnabled: false,
          emailFrequency: 'daily-digest',
        }),
      ).not.toThrow();
    });

    it('should throw for empty userId', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: '' }),
      ).toThrow('userId is required');
    });

    it('should throw for whitespace-only userId', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: '   ' }),
      ).toThrow('userId is required');
    });

    it('should accept valid email frequencies', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: 'user-1', emailFrequency: 'immediate' }),
      ).not.toThrow();
      expect(() =>
        validateCreatePreferencesInput({ userId: 'user-1', emailFrequency: 'daily-digest' }),
      ).not.toThrow();
      expect(() =>
        validateCreatePreferencesInput({ userId: 'user-1', emailFrequency: 'weekly-digest' }),
      ).not.toThrow();
    });
  });

  describe('validateUpdatePreferencesInput', () => {
    it('should accept empty input', () => {
      expect(() => validateUpdatePreferencesInput({})).not.toThrow();
    });

    it('should accept valid emailEnabled', () => {
      expect(() =>
        validateUpdatePreferencesInput({ emailEnabled: false }),
      ).not.toThrow();
    });

    it('should accept valid emailFrequency', () => {
      expect(() =>
        validateUpdatePreferencesInput({ emailFrequency: 'weekly-digest' }),
      ).not.toThrow();
    });
  });
});

