+import { describe, it, expect } from 'vitest';
+import {
+  validateCreatePreferencesInput,
+  validateUpdatePreferencesInput,
+} from '../../src/validators/preferences.validator.js';
+
+describe('Preferences Validators', () => {
+  describe('validateCreatePreferencesInput', () => {
+    it('should accept valid input with only userId', () => {
+      expect(() =>
+        validateCreatePreferencesInput({ userId: 'user-1' }),
+      ).not.toThrow();
+    });
+
+    it('should accept valid input with all fields', () => {
+      expect(() =>
+        validateCreatePreferencesInput({
+          userId: 'user-1',
+          emailEnabled: false,
+          emailFrequency: 'daily-digest',
+        }),
+      ).not.toThrow();
+    });
+
+    it('should throw for empty userId', () => {
+      expect(() =>
+        validateCreatePreferencesInput({ userId: '' }),
+      ).toThrow('userId is required');
+    });
+
+    it('should throw for whitespace-only userId', () => {
+      expect(() =>
+        validateCreatePreferencesInput({ userId: '   ' }),
+      ).toThrow('userId is required');
+    });
+
+    it('should accept valid email frequencies', () => {
+      expect(() =>
+        validateCreatePreferencesInput({ userId: 'user-1', emailFrequency: 'immediate' }),
+      ).not.toThrow();
+      expect(() =>
+        validateCreatePreferencesInput({ userId: 'user-1', emailFrequency: 'daily-digest' }),
+      ).not.toThrow();
+      expect(() =>
+        validateCreatePreferencesInput({ userId: 'user-1', emailFrequency: 'weekly-digest' }),
+      ).not.toThrow();
+    });
+  });
+
+  describe('validateUpdatePreferencesInput', () => {
+    it('should accept empty input', () => {
+      expect(() => validateUpdatePreferencesInput({})).not.toThrow();
+    });
+
+    it('should accept valid emailEnabled', () => {
+      expect(() =>
+        validateUpdatePreferencesInput({ emailEnabled: false }),
+      ).not.toThrow();
+    });
+
+    it('should accept valid emailFrequency', () => {
+      expect(() =>
+        validateUpdatePreferencesInput({ emailFrequency: 'weekly-digest' }),
+      ).not.toThrow();
+    });
+  });
+});

