+import { describe, it, expect } from 'vitest';
+import {
+  validateEmail,
+  validateCreateUserInput,
+  validateUpdateUserInput,
+} from '../../src/validators/user.validator.js';
+
+describe('User Validators', () => {
+  describe('validateEmail', () => {
+    it('should accept valid email', () => {
+      expect(() => validateEmail('alice@example.com')).not.toThrow();
+    });
+
+    it('should accept email with subdomain', () => {
+      expect(() => validateEmail('alice@mail.example.com')).not.toThrow();
+    });
+
+    it('should reject email without @', () => {
+      expect(() => validateEmail('aliceexample.com')).toThrow('Invalid email format');
+    });
+
+    it('should reject email without domain', () => {
+      expect(() => validateEmail('alice@')).toThrow('Invalid email format');
+    });
+
+    it('should reject email without local part', () => {
+      expect(() => validateEmail('@example.com')).toThrow('Invalid email format');
+    });
+
+    it('should reject empty string', () => {
+      expect(() => validateEmail('')).toThrow('Invalid email format');
+    });
+
+    it('should reject email with spaces', () => {
+      expect(() => validateEmail('alice @example.com')).toThrow('Invalid email format');
+    });
+  });
+
+  describe('validateCreateUserInput', () => {
+    it('should accept valid input', () => {
+      expect(() =>
+        validateCreateUserInput({
+          name: 'Alice',
+          email: 'alice@example.com',
+          role: 'member',
+        }),
+      ).not.toThrow();
+    });
+
+    it('should throw for empty name', () => {
+      expect(() =>
+        validateCreateUserInput({
+          name: '',
+          email: 'alice@example.com',
+          role: 'member',
+        }),
+      ).toThrow('User name is required');
+    });
+
+    it('should throw for whitespace-only name', () => {
+      expect(() =>
+        validateCreateUserInput({
+          name: '   ',
+          email: 'alice@example.com',
+          role: 'member',
+        }),
+      ).toThrow('User name is required');
+    });
+
+    it('should throw for invalid email', () => {
+      expect(() =>
+        validateCreateUserInput({
+          name: 'Alice',
+          email: 'not-an-email',
+          role: 'member',
+        }),
+      ).toThrow('Invalid email format');
+    });
+  });
+
+  describe('validateUpdateUserInput', () => {
+    it('should accept valid partial input', () => {
+      expect(() => validateUpdateUserInput({ name: 'Bob' })).not.toThrow();
+    });
+
+    it('should accept empty input (no changes)', () => {
+      expect(() => validateUpdateUserInput({})).not.toThrow();
+    });
+
+    it('should throw for empty name', () => {
+      expect(() => validateUpdateUserInput({ name: '' })).toThrow(
+        'User name cannot be empty',
+      );
+    });
+
+    it('should throw for invalid email', () => {
+      expect(() =>
+        validateUpdateUserInput({ email: 'bad-email' }),
+      ).toThrow('Invalid email format');
+    });
+
+    it('should accept valid email update', () => {
+      expect(() =>
+        validateUpdateUserInput({ email: 'new@example.com' }),
+      ).not.toThrow();
+    });
+  });
+});
